`ifndef GUARD_SVT_SPI_TRANSACTION_SV
`define GUARD_SVT_SPI_TRANSACTION_SV 

`include "svt_spi_defines.svi"
// =============================================================================
/**
 * SPI Transaction.
 */
class svt_spi_transaction extends `SVT_TRANSACTION_TYPE;

  /**
    @grouphdr spi_trans_std Standard SPI and Multilane SPI attributes
    This group contains attributes which are relevant to STD SPI and Multilane SPI
    This also contains common parameters between SPI Modes.
    */

  /**
    @grouphdr spi_trans_flash SPI Flash attributes
    This group contains attributes which are relevant to SPI Flash
    */

  /**
    @grouphdr spi_trans_empspi EMPSPI attributes
    This group contains attributes which are relevant to EMPSPI.
    EMPSPI is custom feature.
    */

  /**
    @grouphdr spi_trans_uwire SPI Microwire attributes
    This group contains attributes which are relevant to SPI Microwire Feature.
    */

  /**
    @grouphdr spi_trans_safespi SAFE SPI attributes
    This group contains attributes which are relevant to SAFE SPI Feature.
    */

  /**
    @grouphdr spi_trans_xSPI xSPI Flash attributes
    This group contains attributes which are relevant to xSPI Flash
    */
  //----------------------------------------------------------------------------
  // Enumerated Types
  //----------------------------------------------------------------------------

  //----------------------------------------------------------------------------
  // Public Data Properties
  //----------------------------------------------------------------------------

  /** Handle to configuration, available for use by constraints. */ 
  svt_spi_configuration cfg = null;

  /** Processing status for the transaction. */ 
  status_enum status = INITIAL;

  /** Object used to hold exceptions for a transaction. */
  svt_spi_transaction_exception_list exception_list = null;

  /** 
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI
   * This signal is valid for SPI_MULTILANE and SPI_FLASH mode.
   * It specifies Wait cycles in between address frame and Read Data. Specified as number of SPI clock cycles.
   * For SPI Flash mode, wait_cycle_count default value is determined based on command type,
   * protocol mode as per datasheet of selected device. User configurable value is obtained from cfg register.
   * Wait phase starts from the next posedge after address phase.
   */
  rand int wait_cycle_count = 0;

  /**
   * @groupname spi_trans_std
   * This field is used in trace file for SPI standard mode, to print the<br/>
   * direction of the transaction, either as TX or RX.<br/>
   */
  svt_spi_types::direction_enum direction;

  //----------------------------------------------------------------------------
  // Random Data Properties
  //----------------------------------------------------------------------------

  /**
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI
   * This field contains the target Slave ID. <br/>
   * Its is applicable only in Master Mode when Master needs to transmit data to one slave in one transfer <br/>
   * and to other slave in next transfer. <br/>
   * This field width will depend on the number of slaves configured in this system by define SVT_SPI_MAX_NUM_SLAVES
   */
  rand int unsigned slave_id = 0;

  /**
   * @groupname spi_trans_flash, spi_trans_xSPI
   * This field specifies the Flash Command code.  <br/>
   * This field along with #flash_protocol_mode must be supplied while
   * submitting flash transaction to the Master Agent
   * For command enums , please svt_spi_types::flash_command_enum <br/>
   */
  rand svt_spi_types::flash_command_enum flash_command = svt_spi_types::NULL_OPCODE;

  /**
   * @groupname spi_trans_flash, spi_trans_xSPI
   * This field specifies the Flash protocol mode(eSPI,Dual IO,Quad IO) <br/>    
   * EXTENDED_SPI : Instruction on One Lane, Address and Data on one/two/four for STD/Dual/Quad respectively. <br/>  
   * DUAL SPI     : Instruction, Address and Data on two lanes. <br/> 
   * QUAD SPI     : Instruction, Address and Data on four lanes. <br/>
   * OCTAL_IO_STR : Instruction, Address and Data on eight lanes in STR Mode. <br/>
   * OCTAL_IO_DTR : Instruction, Address and Data on eight lanes in DTR Mode. 
   */
  rand svt_spi_types::flash_protocol_mode_enum flash_protocol_mode;
  
  /**
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI
   * This field contains the actual Data to be transmitted. <br/>
   * This field width will depend on the value of data width configured in this system by define SVT_SPI_DATA_WIDTH.
   */
  rand bit[`SVT_SPI_DATA_WIDTH-1:0] data[];

  /**
   * @groupname spi_trans_flash, spi_trans_xSPI
   * This field contains the Data mask bits. Supported only for flash Mode with DM feature support like apmemory <br/>
   * This field width will depend on the value of data width configured in this system by define SVT_SPI_DATA_WIDTH. <br/>
   * data_valid = 1 : Denotes that corresponding Index in data[] array is valid. <br/>
   * data_valid = 0 : Denotes that corresponding Index in data[] array is not valid. <br/>
   * If size of data_valid is 0, all indexes in data[] are valid.
   */
  rand bit[`SVT_SPI_DATA_WIDTH-1:0] data_valid[];

  /** 
   * @groupname spi_trans_flash
   * Memory upper partition data for X16 mode. <br/>
   * The size of this array is specified by svt_spi_mem_mode_register_configuration::mem_data_partition_size.
   */ 
  rand svt_spi_mem_data_partition mem_upper_data_partition[];

  /**
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI
   * Transmit delay: Number of clock delay before Master initiates transaction on
   * SPI Bus. The delay is applicable only for Master Mode.
   */
  rand int transmit_delay = 10;

  /**
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI
   * This field specifies the number of bits in an instruction phase. <br/>
   * This is valid only when either frame_format is set to SPI_MULTILANE/SPI_FLASH or <br/>
   * frame_format is set to SPI_STD with transfer_mode is set to EEPROM_READ .
   */
  rand int instruction_frame_size = 8;

  /**
   * @groupname spi_trans_flash
   * This field specifies the number of attribute bits transmitted along with #instruction_frame <br/>
   * during Instruction Phase of the device.
   * The value is less than or equal to macro SVT_SPI_ATTRIBUTE_BIT_WIDTH. <br/>
   */
  rand int attribute_bit_size = 0;

  /**
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI
   * This field specifies the number of bits in Address phase. <br/>
   * This is valid only when either frame_format is set to SPI_MULTILANE/SPI_FLASH or <br/>
   * frame_format is set to SPI_STD with transfer_mode is set to EEPROM_READ or <br/>
   * frame_format is set to SPI_STD with enable_mem_core set.
   */
  rand int address_frame_size = 24;

  /**
   * @groupname spi_trans_flash
   * This field specifies the number of wrap bits transmitted along with #address_frame <br/>
   * during Address phase of NAND Flash Device. <br/>
   * The value is less than or equal to macro SVT_SPI_MAX_WRAP_CFG_BIT_WIDTH. <br/>
   */ 
  rand int wrap_mode_bit_size = 0;

  /**
   * @groupname spi_trans_flash
   * This field specifies the number of plane select bits transmitted along with #address_frame <br/>
   * during Address phase of NAND Flash Device. <br/>
   * The value is less than or equal to macro SVT_SPI_MAX_PLANE_SELECT_CFG_BIT_WIDTH. <br/>
   */ 
  rand int plane_select_bit_size = 0;

  /**
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI
   * This field specifies the number of DATA bytes in Data phase. <br/>
   * This is valid only when either frame_format is set to SPI_MULTILANE/SPI_FLASH or <br/>
   * frame_format is set to SPI_STD with transfer_mode is set to EEPROM_READ . <br/>
   */
  rand int unsigned data_frame_size = 0;

  /**
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI
   * This field contains the instruction frame bits to be transmitted in instruction phase. <br/>
   * The number of instruction bytes transmitted are specified by #instruction_frame_size. <br/>
   * Ex: If value of #instruction_frame_size is 8 then bit [7:0] of #instruction_frame will be transmitted.
   */
  rand bit [`SVT_SPI_MAX_INST_FRAME_WIDTH-1:0] instruction_frame = `SVT_SPI_MAX_INST_FRAME_WIDTH'h0;

  /**
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI
   * This field contains the address frame bytes to be transmitted in address phase. <br/>
   * The number of address bytes transmitted are specified by #address_frame_size. <br/>
   */
  rand bit [`SVT_SPI_MAX_ADDR_FRAME_WIDTH-1:0] address_frame = `SVT_SPI_MAX_ADDR_FRAME_WIDTH'h0;

  /**
   * @groupname spi_trans_flash
   * This field specifies the wrap configuration bits transmitted along with #address_frame
   * during Address phase of NAND Flash Device. <br/>
   */ 
  rand bit [`SVT_SPI_MAX_WRAP_CFG_BIT_WIDTH-1:0] wrap_mode; 
  
  /**
   * @groupname spi_trans_flash
   * This field specifies the plane select value transmitted along with #address_frame
   * during Address phase of NAND Flash Device. <br/>
   */ 
  rand bit [`SVT_SPI_MAX_PLANE_SELECT_CFG_BIT_WIDTH-1:0] plane_select; 

  /**
   * @groupname spi_trans_flash
   * This Read Only field contains the Device Physical Address where the Memory has been updated/Read.
   * This can be used in Analysis port and Scoreboarding purposes.
   */ 
  bit [`SVT_SPI_MAX_ADDR_FRAME_WIDTH-1:0] chip_phy_address;

  /**
   * @groupname spi_trans_flash
   * This Read Only field contains the Transmitted/Received Address CRC byte <br/>
   * along with #address_frame during Address phase of NOR Flash Device. <br/>
   * CRC is calculated inside VIP when Register Configuration Enable CRC is ON.
   */
  bit [`SVT_SPI_MAX_ADDR_CRC_BIT_WIDTH-1:0] address_crc;

  /**
   * @groupname spi_trans_flash
   * This Read Only field contains the Transmitted/Received Data CRC bytes <br/>
   * along with #data during Data phase of NOR Flash Device. <br/>
   * CRC is calculated inside VIP when Register Configuration Enable CRC is ON.
   */
  bit[`SVT_SPI_DATA_WIDTH-1:0] data_crc[];

  /**
   * @groupname spi_trans_safespi
   * This Read Only field contains the Transmitted/Received CRC frame.<br/>
   * CRC is calculated inside VIP, before transmitting the spi_safe_frame.<br/>
   * At the reciever, the recieved CRC is compared against the CRC calculated<br/>
   * on the recieved spi_safe_frame.
   */
  bit [`SVT_SPI_SAFE_MAX_FRAME_WIDTH-1:0] spi_safe_crc_frame;

  /**
   * @groupname spi_trans_flash
   * This field specifies whether master should assert the dedicated Vpp port during the <br/>
   * current Program/Erase command. This is valid only when enable_dedicated_vpp_port bit  <br/>
   * is asserted in Mode register configuration class for selected device. <br/>
   */ 
  rand bit vpp;

  /** @cond PRIVATE */
  /**
   * @groupname spi_trans_std
   * Address and instruction transfer format :-
   * Selects whether SPI will transmit instruction/address in Standard SPI mode or the SPI mode selected in SPI_FRF field.
   * 
   * 00 - Instruction and Address will be sent in Standard SPI Mode.
   * 01 - Instruction will be sent in Standard SPI Mode and Address will be sent in the mode specified by SPI_FRF.
   * 10 - Both Instruction and Address will be sent in the mode specified by SPI_FRF. .
   */
  rand bit [1:0] spi_transaction_mode = 2'b00;
  /** @endcond */

  /**
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI
   * This field specifies the number of lanes over which Instruction phase bits are to be transmitted. <br/>
   * This can take values 1,2,4,.... <br/>
   * It should be integral multiple of #instruction_frame_size <br/>
   */
  rand int instruction_lane_count = 1;

  /**
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI
   * This field specifies the number of lanes over which Address phase bits are to be transmitted. <br/>
   * This can take values 1,2,4,.... <br/>
   * It should be integral multiple of #address_frame_size <br/>
   */
  rand int address_lane_count = 1;

  /**
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI
   * This field specifies the number of lanes over which Data phase bits are to be transmitted. <br/>
   * This can take values 1,2,4,.... <br/>
   * It should be integral multiple of #data_frame_size <br/>
   */
  rand int data_lane_count = 1;

  /**
   * @groupname spi_trans_flash, spi_trans_flash, spi_trans_xSPI
   * This field specifies the number of lanes over which bits are valid during Wait/dummy cycle phase <br/>
   * The value of this field depends on Flash command in progress <br/>
   */
  rand int wait_cycle_lane_count = 1;

  /**
   * @groupname spi_trans_flash, spi_trans_flash, spi_trans_xSPI
   * It specifies clock cycles in between wait cycles and Read Data. Specified as number of SPI clock cycles. <br/>
   * For SPI Flash mode, pre_data_cycle_count default value is determined based on command type, <br/>
   * protocol mode as per datasheet of selected device.
   */
  rand int pre_data_cycle_count = 0;

  /**
   * @groupname spi_trans_flash, spi_trans_flash, spi_trans_xSPI
   * This field specifies the number of lanes over which bits are valid during Pre Data cycle phase <br/>
   * The value of this field depends on Flash command in progress 
   */
  rand int pre_data_cycle_lane_count = 1;

  /**
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI
   * Transfer Mode.  
   * Used to select the mode of transfer for serial communications when full-duplex serial protocols are used (SPI or SSP). This field does not affect the transfer’s duplex. Only indicates whether the receive/transmit data is valid. <br/> 
   * In ‘transmit only’ mode (0x00), data received from the external device is not stored, and is overwritten on the next transfer. <br/> 
   * In ‘receive only’ mode (0x01), transmitted data is not valid. The programmed word is transmitted for the duration of the transfer. <br/> 
   * In ‘transmit and receive’ mode(0x10), both transmit and receive data are valid. <br/> 
   * In EEPROM Read (0x11), Master ignores the received Data until Address phase is completed.<br/> 
   * when Slave configuration is selected with EEPROM Mode, Data output from slave begins immediately after Address phase completes. Slave Agent uses Instruction_frame_size & Address_frame_size to determine the end of Instruction phase and address phase <br/>.
   * 
   * When frame_format is set to SPI_MULTILANE, There are only two valid combinations: <br/> 
   * 01 - Write <br/> 
   * 10 - Read  <br/> 
   * In Write Mode, supported phases are Instruction phase, Address phase and Data phase. <br/>
   * In Read Mode, supported phases are Instruction phase, Address phase, Wait Cycle Phase and Data phase. <br/>
   * 
   * When frame_format is set to SPI_STD and spi_feature set as UWIRE (MicroWire), There are only two valid combinations: <br/> 
   * 00 - Receive <br/> 
   * 01 - Transmit  <br/> 
   * In Transmit Mode, the data word is transmitted to the external device. <br/> 
   * In Receive Mode, the data word is received from the external device. <br/>
   * For Master and Slave to communicate across MicroWire, Devices must be <br/>
   * programmed complementary to each other. i.e. Either Master in Transmit mode and <br/>
   * Slave in Receive mode or Master in Receive mode and Slave in Transmit mode.<br/>
   * Master always start the transfer by transmitting Control word.<br/>
   * When Master is configured for Transmit mode, It transmits Data Word after completing transfer of Control word. <br/>
   * The Sequence of Control words and Data words is controlled by #uwire_transfer_state <br/>
   * When Slave is configured for Transmit mode, It expects Control word <br/>
   * from Master first. After Control word is sampled, Slave transmit bit '0' during dummy phase followed by Data byte.<br/> 
   * When Master is configured for Receive mode, It expects dummy phase followed by Data bytes from Slave. <br/>
   * When Slave is configured for Receive mode, It latch Data bytes soon after control word phase is completed. <br/>
   *
   */
  rand bit [1:0] transfer_mode = 2'b01;

  /** @cond PRIVATE */
  /**
   * @groupname spi_trans_std
   * Output enable in the Bidirectional mode of operation <br/>
   * This bit controls the MOSI and MISO output buffer of the SPI, when in bidirectional mode of operation (SPC0 is set). <br/>
   * In master mode this bit controls the output buffer of the MOSI port. <br/>
   * In slave mode it controls the output buffer of the MISO port. <br/>
   * 1 = Output buffer enabled <br/>
   * 0 = Output buffer disabled . <br/>
   */
  rand bit spi_bidiroe = 0;
  /** @endcond */

  /**
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI 
   * This field is used to select Double Transfer Rate(DTR) mode in VIP. Also known as DDR mode. <br/>
   * This mode is not applicable for Wait Cycle(Dummy cycle) phase. <br/>
   * In SPI_STD and SPI_MULTILANE mode, the phases in which this field is applicable depends on field svt_spi_configuration::dtr_mode_select. <br/>
   * Its applicable either in data only, address-data phase or inst-address-data phase. <br/>
   * 1 = DTR enabled <br/>
   * 0 = DTR disabled <br/>
   */
  rand bit double_transfer_rate_mode = 1'b0;

  /**
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI
   * Minimum leading time before the first clock edge.  <br/>
   * It is in multiple of half interface signal <a href="interfaces.html\#item_svt_spi_if_sclk"> sclk </a> . <br/>
   * ss_n and SPI_CSN refer to the same signal.
   */
  rand int timer_leading = 1;

  /**
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI
   * Minimum trailing time after the last clock edge. <br/>
   * It is in multiple of half interface signal <a href="interfaces.html\#item_svt_spi_if_sclk"> sclk </a> . <br/>
   */
  rand int timer_trailing = 1;

  /**
   * @groupname spi_trans_std, spi_trans_flash, spi_trans_xSPI
   * Minimum idling time between transfers (minimum SS high time). <br/>
   * It is in multiple of half interface signal <a href="interfaces.html\#item_svt_spi_if_sclk"> sclk </a> . <br/>
   */
  rand int timer_idling_between_transfers = 1;

  /** @cond PRIVATE */
  /** 
   * @groupname spi_trans_empspi
   * Time from slave assert SPI_INT to master assert ss_n (DirectRead) .<br/>
   * It is in multiple of interface signal <a href="interfaces.html\#item_svt_spi_if_sclk"> sclk </a> . <br/>
   */
  rand int timer_assert_spi_int_to_spi_ssn = 1;

  /** 
   * @groupname spi_trans_empspi
   * Time from master assert ss_n to slave assert SPI_INT (DirectWrite) . <br/>
   * It is in multiple of interface signal <a href="interfaces.html\#item_svt_spi_if_bus_clk"> bus_clk </a> . <br/>
   */
  rand int timer_assert_spi_ssn_to_spi_int = 1;
  /** @endcond */

  /** @cond PRIVATE */
  /** 
   * @groupname spi_trans_empspi
   * Time from last sample on MOSI/MISO to slave deassert SPI_INT . <br/>
   * It is in multiple of interface signal <a href="interfaces.html\#item_svt_spi_if_bus_clk"> bus_clk </a> . <br/>
   */
  rand bit[3:0] timer_last_sample_to_spi_int_deassert = 1;

  /** 
   * @groupname spi_trans_empspi
   * Time Master will hold SPI_CSN high until it sees SPI_INT continuously high for #timer_empspi_slave_hold_spi_int.<br/>
   * It is in multiple of interface signal <a href="interfaces.html\#item_svt_spi_if_bus_clk"> bus_clk </a> . <br/>
   */
  rand bit[3:0] timer_empspi_master_hold_spi_ssn = 1;

  /** 
   * @groupname spi_trans_empspi
   * Time Slave will hold SPI_INT high until it sees SPI_CSN continuously high for #timer_empspi_master_hold_spi_ssn.<br/>
   * It is in multiple of interface signal <a href="interfaces.html\#item_svt_spi_if_bus_clk"> bus_clk </a> . <br/>
   */
  rand bit[3:0] timer_empspi_slave_hold_spi_int = 1;

  /** 
   * @groupname spi_trans_empspi
   * Time Master Agent wait for Slave Device to assert SP_INT for DIRECT READ 
   * Command. If SPI_INT is not asserted by slave until timer expires then
   * Master go ahead and asserts the SS_n 
   */
  rand bit [4:0] timer_empspi_mstr_spi_int_assert_timeout = 5'd10;
  
  /** 
   * @groupname spi_trans_empspi
   * Internal Time taken by Slave Agent to assert the SPI_INT on SPI Bus for DIRECT READ. <br/>
   * It is in multiple of interface signal <a href="interfaces.html\#item_svt_spi_if_bus_clk"> bus_clk </a> . <br/>
   */
  rand bit [4:0] timer_empspi_spi_int_transmit_delay = 5'd8;
  /** @endcond */

  /** @cond PRIVATE */
  /** 
   * @groupname spi_trans_empspi
   * This register is used in EMPSPI mode and Generic Master mode.  In EMPSPI mode when FW has loaded all data and is ready to send it, <br/>
   * FW should write the total number of bytes written to the FIFO to this register.In Generic Master mode, writing to this register tells<br/> 
   * the hardware to send and/or receive this many bytes.  Whether the hardware sends or receives depends on whether<br/> 
   * the TXFIFO_EN and RXFIFO_EN bits are set in the spiffy_cfg register. */
  rand int empspi_transmission_length = 8;
  /** @endcond */
  
  /** @cond PRIVATE */
  /** 
   * @groupname spi_trans_empspi
   * This bit specifes whether EMPSPI slave should repond to DIRECT READ with zero length data.
   * This Mode is applicable for EMPSPI Mode with Slave mode. 
   */
  rand bit empspi_unsolicited_read = 1'b0;
  /** @endcond */

  /**
   * @groupname spi_trans_flash, spi_trans_xSPI
   * This field specifies the Flash command category
   */
  rand svt_spi_types::flash_command_type_enum flash_command_type;

  /**
   * @groupname spi_trans_xSPI
   * This field specifies the xSPI Profile Type category
   */
  rand svt_spi_types::xSPI_profile_type_enum xSPI_profile_type = svt_spi_types::NO_PROFILE;

  /**
   * @groupname spi_trans_flash, spi_trans_xSPI
   * This field specifies XIP confirmation bit/continuous read mode value to be used during wait phase <br/> 
   * for FAST Read commands when XIP mode is enabled. <br/>
   * For Vendor Micron,only LSB of this bitvector is valid. <br/>
   * For Vendor Winbond, MSB[7:4] of the bitvector specifies the upper 4 bits of continuous read mode.
   */
  rand bit[7:0] xip_confirmation_n = 8'b1;

  /**
   * @groupname spi_trans_flash, spi_trans_xSPI
   * This field specifies the Write protect feature to be used while writing to Status Register
   * This can be used for Extended and Dual IO modes
   */
  rand bit write_protect_n = 1'b1;

  /**
   * @groupname spi_trans_flash
   * This field specifies that id Device ID is to transmitted in command RELEASE_FROM_DEEP_POWER_DOWN
   * This is applicable for vendor Winbond ,Adesto and Macronix.
   */
  rand bit read_device_id_with_power_down = 1'b1;

  /**
   * @groupname spi_trans_flash
   * This field is valid only for SPI Flash Master mode. <br/>
   * It specifies sample/transmit edge count after which hold request is asserted by Flash Controller/MasterAgent. <br/>
   * Transmit or Recieve edge selection is based on configuration field 'activate_hold_when_clock_low' <br/> 
   * The upper limit value for this control field is penultimate(second last) sample/transmit edge for the current SPI Flash transaction <br/>
   * Hold Request is asserted after (#flash_assert_hold_after_sclk_count + #flash_sclk_to_hold_assert) delay  
   */
  rand int flash_assert_hold_after_sclk_count = 1;
  
  /**
   * @groupname spi_trans_flash
   * This field is valid only for SPI Flash Master mode. <br/>
   * It specifies SCLK edge (specified by #flash_assert_hold_after_sclk_count) to hold assert delay (tCHHL). This delay <br/>
   * is specified in multiple of #bus_clk half cycle.  <br/>
   * Its minimum supported value is '1' and maximum supported value is (baud_rate_divisor-1). <br/>
   * Hold Request is asserted after (#flash_assert_hold_after_sclk_count + #flash_sclk_to_hold_assert) delay  
   */
  rand int flash_sclk_to_hold_assert = 1;

  /**
   * @groupname spi_trans_flash
   * This field is valid only for SPI Flash Master mode. <br/>
   * It specifies sclk edge to hold deassert delay. This delay <br/> 
   * is specifies in multiple of #bus_clk half cycle <br/>
   * Its minimum supported value is '1' and maximum supported value is (baud_rate_divisor-1). <br/>
   * Hold Request is de-asserted after (#flash_hold_command_hold_time_sclk + #flash_sclk_to_hold_deassert) delay  
   */
  rand int flash_sclk_to_hold_deassert = 1;

  
  /**
   * @groupname spi_trans_flash
   * This field is valid only for SPI Flash Master mode. <br/>
   * It is specified in multiple of Sample/Transmit sclk edge  <br/>
   * Hold Request is de-asserted after (#flash_hold_command_hold_time_sclk + #flash_sclk_to_hold_deassert) delay <br/> 
   */
  rand int flash_hold_command_hold_time_sclk = 1;

  /**
   * @groupname spi_trans_flash, spi_trans_xSPI
   * Each item of this dynamic array specify the index of SCLK edge from beginning of transaction <br/>
   * when pause will be inserted on SPI Interface. <br/>
   * This is applicable when configuration parameter #enable_sclk_pause_feature is set to 1. <br/>
   * It is specified in multiple of Sample/Transmit sclk edge  <br/>
   * SCLK Pause index must be specified in ascending order. <br/>
   * Default : 0 
   */ 
  rand int sclk_pause_after_sclk_count [];

  /**
   * @groupname spi_trans_flash, spi_trans_xSPI
   * Each item of this dynamic array specify the duration for which pause will be inserted on SPI Interface. <br/>
   * This is applicable when configuration parameter #enable_sclk_pause_feature is set to 1. <br/>
   * This value should be greater than the baud rate divisor. <br/>
   * It is specified in multiple of #bus_clk half cycle.  <br/>
   * The size of this array should be same as #sclk_pause_after_sclk_count <br/>
   * Default : 0 
   */
  rand int sclk_pause_duration [];

  /**
   * @groupname spi_trans_flash
   * This field is used internally for randomization purpose.
   */
  rand int total_transmit_edge;

  rand int total_sclk_edge;

  /**
   * @groupname spi_trans_flash
   * It Specifies the length of XIP Reset sequence/ Protocol Reset Sequence.
   */
  rand int flash_reset_sequence_length = 0;

  /**
   * @groupname spi_trans_flash
   * It Specifies the value of Attribute Bit field used in the FLASH Command: TUNING_DATA_PATTERN_OPERATION <br/>
   * Default Value: 8'h0
   */
  rand bit [`SVT_SPI_ATTRIBUTE_BIT_WIDTH-1:0] flash_attribute_bits = `SVT_SPI_ATTRIBUTE_BIT_WIDTH'h0;

  /**
   * @groupname spi_trans_flash, spi_trans_xSPI
   * This field specifes the status of SPI Flash command received by SPI Flash
   * device.  <br/>
   * The status is updated for packet reported through analysis  <br/>
   * port and can be used as control flag while scoreboarding with device memory
   * contents,
   */
  svt_spi_types::flash_status_enum flash_status = svt_spi_types::OPERATION_SUCCESS; 

  /**
   * @groupname spi_trans_safespi
   * This Read Only field specifies the status of safe SPI request, received by safe SPI 
   * device.  <br/>
   * The status is updated for packet reported through analysis  <br/>
   * port and can be used as control flag while scoreboarding common chip
   * select configured device.
   */
  svt_spi_types::spi_safe_status_enum spi_safe_status = svt_spi_types::SLAVE_SELECT_ADDR_MATCHED; 

  /**
   * @groupname spi_trans_flash
   * This field specifies the Block/Page Address received by SPI Flash device. <br/>
   * This is a Read-Only field.
   */
  bit[`SVT_SPI_MAX_ADDR_FRAME_WIDTH-1:0] nand_cache_page_address;

  /**
   * @groupname spi_trans_uwire
   * This field is valid only for SPI Feature as Microwire(UWIRE). <br/>
   * This field specifies the number of Control Words to be transmitted in Control Word phase. <br/>
   * In NON-Sequential transfer state(#uwire_transfer_state), number of Control Words can be any random value. <br/>
   * In Sequential transfer state(#uwire_transfer_state), number of Control Words can only be 1.
   */
  rand int unsigned uwire_control_word_size = 0;

  /**
   * @groupname spi_trans_uwire
   * This field is valid only for SPI Feature as Microwire(UWIRE). <br/>
   * Transfer state. <br/> 
   * Used to determine whether the Microwire transfer state is Sequential or Non-Sequntial.  <br/> 
   * In ‘NON_SEQUENTIAL’ state, there must be a control word for each data word that is transmitted or received. <br/> 
   * In ‘SEQUENTIAL’ state, only one control word is needed to transmit or receive a block of data words. <br/> 
   */
  rand svt_spi_types::uwire_transfer_state_enum uwire_transfer_state = svt_spi_types::NON_SEQUENTIAL;

  /**
   * @groupname spi_trans_uwire
   * This field is valid only for SPI Feature as Microwire(UWIRE). <br/>
   * This field contains the Control Words to be transmitted and size of Control Word array depends on #uwire_control_word_size value. <br/>
   * The width of a Control Word will depend on the value of Control Word Width configured in this system by #SVT_SPI_UWIRE_MAX_CONTROL_WORD_WIDTH.
   */
  rand bit[`SVT_SPI_UWIRE_MAX_CONTROL_WORD_WIDTH-1:0] uwire_control_word[];

  /**
   * @groupname spi_trans_uwire
   * This field is valid only for SPI Feature as Microwire(UWIRE). <br/>
   * This field specifies the number of lanes over which Control Word phase bits are to be transmitted. <br/>
   * The valid value for this field for UWIRE is 1. <br/>
   */
  rand int uwire_control_word_lane_count = 1;

  /**
   * @groupname spi_trans_uwire
   * This field is valid only for SPI Feature as Microwire(UWIRE). <br/>
   * This field is used to determine the transfer complete status. Once this bit is set, Master will transmit Start bit to clear the ready status  <br/>
   * of the slave before completing the transfer.
   */
  rand bit uwire_deassert_start_bit = 1'b0;

  /**
   * @groupname spi_trans_safespi
   * This field specifies the number of bits in a SAFE SPI Frame. <br/>
   * This is valid only when frame_format is set to SPI_SAFE.
   */
  rand int spi_safe_frame_size = 0;

  /**
   * @groupname spi_trans_safespi
   * For Master Devices, this field contains #spi_safe_frame_size bit frame which contains the following:
   * IN_FRAME : spi_safe_frame[31:27] contains Target Address <br/>
   *            spi_safe_frame[26: 5] contains freely defined data <br/>
   *            spi_safe_frame[ 4: 2] will be replaced by CRC calculated by VIP. <br/>
   *            safsafe 1: 0] contains freely defined data <br/>
   * OUT_OF_FRAME : spi_safe_frame[31:22] contains Target Address <br/>
   *            spi_safe_frame[21: 3] contains freely defined data <br/>
   *            spi_safe_frame[ 2: 0] will be replaced by CRC calculated by VIP. <br/>
   *
   * For Slave Devices, this field contains 32 bit frame which contains the following:
   * IN_FRAME : When Sensor data is to be transmitted, spi_safe_frame[19:4] contains Sensor data <br/>
   *            When other data is to be transmitted, spi_safe_frame[20:3] contains freely defined data <br/>
   *            Rest all fields will be replaced by VIP. <br/>
   * OUT_OF_FRAME : When Sensor data is to be transmitted, spi_safe_frame[19:4] contains Sensor data and <br/>
   *                spi_safe_frame[25:21] contains Source Address[4:0] data <br/>
   *                When other data is to be transmitted, spi_safe_frame[20:3] contains freely defined data and <br/>
   *                spi_safe_frame[25:21] contains Source Address[4:0] data <br/>
   *            Rest all fields will be replaced by VIP.
   */ 
  rand bit[`SVT_SPI_SAFE_MAX_FRAME_WIDTH-1:0] spi_safe_frame;

  /** 
   * @groupname spi_trans_flash
   * This field specifies whether the parallel mode is enabled for current flash command. <br/>
   * This is currently valid only for Macronix part number MX25L12865E. 
   */
  rand bit parallel_mode = 1'b0;

  /** 
   * @groupname spi_trans_xSPI
   * This field specify the Index of xSPI Command list svt_spi_mem_mode_register_configuration::xSPI_command_list . <br/>
   * selected in current transaction <br/>
   * Default Value : -1
   */
  rand int xSPI_command_list_index = -1;

  /** 
   * @groupname spi_trans_xSPI
   * This field specify the Protocol Mode's Index of xSPI Command list svt_spi_mem_mode_register_configuration::xSPI_command_list . <br/>
   * selected in current transaction <br/>
   * Default Value : -1
   */
  rand int xSPI_command_list_protocol_mode_index = -1;

  /**
   * @groupname spi_trans_flash, spi_trans_xSPI
   * This Read Only field contains the list of Beat Address(es) which are accessed in a beat. <br/>
   * This will be updated when Monitor Callback "beat_ended" is triggeed. <br/>
   * The index matches with corresponding #current_beat_data. <br/>
   * Ex: Memory address pointed by current_beat_address[i] contains data of current_beat_data[i].
   */ 
  bit [`SVT_SPI_MAX_ADDR_FRAME_WIDTH-1:0] current_beat_address[];

  /**
   * @groupname spi_trans_flash, spi_trans_xSPI
   * This Read Only field contains the list of Beat Data(s) which are accessed in a beat. <br/>
   * This will be updated when Monitor Callback "beat_ended" is triggeed. <br/>
   * The index matches with corresponding #current_beat_data. <br/>
   * Ex: Memory address pointed by current_beat_address[i] contains data of current_beat_data[i].
   */ 
  bit [`SVT_SPI_DATA_WIDTH-1:0] current_beat_data[];

  /**
   * @groupname spi_trans_xSPI
   * This Read Only field contains the list of Beat Data Valids(s) which are accessed in a beat. <br/>
   * This will be updated when Monitor Callback "beat_ended" is triggeed. <br/>
   * The index matches with corresponding #current_beat_data and #current_beat_data. <br/>
   * Ex: Memory address pointed by current_beat_address[i] contains data of current_beat_data[i] with current_beat_data_valid[i]. <br/>
   * This is currently updated for xSPI Profile 2.0 Mode Only
   */
  bit [`SVT_SPI_DATA_WIDTH-1:0] current_beat_data_valid[];

  /**
   * @groupname spi_trans_flash, spi_trans_xSPI
   * This Read Only field contains the actual memory addresses which have been accessed for Read/Write Memory. <br/>
   * This field gets populated when Monitor Callback "transaction_ended" is triggered. <br/>
   * The index matches with corresponding #beat_data_list. <br/>
   * This field width will depend on the value of data width configured in this system by SVT_SPI_MAX_ADDR_FRAME_WIDTH.
   */
  bit [`SVT_SPI_MAX_ADDR_FRAME_WIDTH-1:0] beat_address_list[];

  /**
   * @groupname spi_trans_flash, spi_trans_xSPI
   * This Read Only field contains the actual memory data which have been accessed for Read/Write Memory. <br/>
   * This field gets populated when Monitor Callback "transaction_ended" is triggered. <br/>
   * The index matches with corresponding #beat_address_list. <br/>
   * This field width will depend on the value of data width configured in this system by SVT_SPI_MAX_ADDR_FRAME_WIDTH.
   */
  bit [`SVT_SPI_DATA_WIDTH-1:0] beat_data_list[];

  /**
   * @groupname spi_trans_xSPI
   * This Read Only field contains the actual memory data valid which have been accessed for Write Memory. <br/>
   * This field gets populated when Monitor Callback "transaction_ended" is triggered. <br/>
   * The index matches with corresponding #beat_address_list and #beat_data_list. <br/>
   * This field width will depend on the value of data width configured in this system by SVT_SPI_MAX_ADDR_FRAME_WIDTH. <br/>
   * This is currently updated for xSPI Profile 2.0 Mode Only
   */
  bit [`SVT_SPI_DATA_WIDTH-1:0] beat_data_valid_list[];

  /**
   * @groupname spi_trans_xSPI
   * This Read only field contains information of current ASO. <br/>
   * This is currently updated for xSPI Profile 2.0 Mode Only
   */
  svt_spi_types::flash_prfl_2_0_aso_type_enum flash_prfl_2_0_aso_type = svt_spi_types::ASO_NONE; 

  svt_spi_types::flash_prfl_2_0_aso_overlaid_enum flash_prfl_2_0_aso_overlaid = svt_spi_types::ASO_NO; 

  /** @cond PRIVATE */
  longint device_max_address_frame_size = 32;

  longint device_max_register_address_frame_size = 32;

  // specifies whether RESET# feature is enabled for selected device.
  bit flash_reset_feature_enable = 0;

  /**
   * @groupname spi_trans_flash
   * This field is used internally for calculation purpose.
   */
  int baud_rate_divisor;
  
  /** @endcond */

  /** 
   * @groupname spi_trans_flash, spi_trans_xSPI
   * This field contains the JEDEC HW reset value to be driven on MOSI lane <br/>
   * Default Value : 0
   */
  rand reg jedec_hw_reset_mosi_state = 0;

  /** 
   * @groupname spi_trans_flash, spi_trans_xSPI
   * This field defines the JEDEC HW Reset Chip Select Low timer value <br/>
   * Timer value is defined in ns.
   * Default Value : 50
   */
  rand int jedec_hw_reset_cs_low_time_ns = 50;

  //----------------------------------------------------------------------------
  // Protected Data Properties
  //----------------------------------------------------------------------------
  //----------------------------------------------------------------------------
  // Local Data Properties
  //----------------------------------------------------------------------------

  //----------------------------------------------------------------------------
  // Constraints
  //----------------------------------------------------------------------------

  /**
   * Valid ranges constraints insure that the transaction settings are supported
   * by the spi components.
   */
  constraint valid_ranges {
    transmit_delay inside {[0:`SVT_SPI_MAX_TRANSMIT_DELAY]};
   
    slave_id < `SVT_SPI_MAX_NUM_SLAVES;
    
    timer_leading inside  {[1:`SVT_SPI_MAX_LEADING_TIME]} ;
   
`protected
