`endprotected


    timer_last_sample_to_spi_int_deassert inside {[0:`SVT_SPI_MAX_LAST_SAMPLE_TO_SPI_INT_DEASSERT]};
    timer_trailing inside {[1:`SVT_SPI_MAX_TRAILING_TIME]};
    
    timer_idling_between_transfers inside {[1:`SVT_SPI_MAX_IDLE_TIME_BETWEEN_TRANSFER]};
   
    if (cfg.spi_feature == svt_spi_types::UWIRE) {
      uwire_control_word_size inside {[1:`SVT_SPI_UWIRE_MAX_CONTROL_WORD_TRANSFER]};
    }
    else {
      uwire_control_word_size == 0;
    } 

    if (cfg.enable_mem_core) {
      data.size == 0;
    }
    else {
      data.size == data_frame_size;
    }


    if (cfg.spi_feature == svt_spi_types::UWIRE) {
      if (cfg.enable_mem_core) {
        uwire_control_word.size == 0; 
      }
      else {
        uwire_control_word.size == uwire_control_word_size;
      }
    }
    else {
      uwire_control_word.size == 0;
    } 

    instruction_lane_count <= `SVT_SPI_IO_WIDTH;  
    address_lane_count <= `SVT_SPI_IO_WIDTH;  
    data_lane_count <= `SVT_SPI_IO_WIDTH; 
    wait_cycle_lane_count <=`SVT_SPI_IO_WIDTH; 
    uwire_control_word_lane_count <=`SVT_SPI_IO_WIDTH; 
    if (cfg.frame_format == svt_spi_types::SPI_FLASH) {
      if(cfg.spi_mem_cfg.mode_register_cfg.enable_xSPI_mode) {
        xSPI_profile_type == get_xSPI_profile_type(flash_command);  
        xSPI_command_list_index == get_xSPI_command_list_index(flash_command,xSPI_profile_type);
        xSPI_command_list_protocol_mode_index == get_xSPI_command_list_protocol_mode_index(flash_protocol_mode,xSPI_command_list_index,xSPI_profile_type);
      }
      else {
        xSPI_profile_type == svt_spi_types::NO_PROFILE;
        xSPI_command_list_index == -1;
        xSPI_command_list_protocol_mode_index == -1;
      }
      jedec_hw_reset_cs_low_time_ns inside {[get_spi_flash_min_jedec_hw_reset_cs_low_time():get_spi_flash_max_jedec_hw_reset_cs_low_time()]};
      parallel_mode inside {get_spi_flash_min_parallel_mode(flash_command),get_spi_flash_max_parallel_mode(flash_command)};
      address_lane_count == get_spi_flash_address_lane_count(flash_protocol_mode,flash_command,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type);
      data_lane_count == get_spi_flash_data_lane_count(flash_protocol_mode,flash_command,parallel_mode,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type);
      wait_cycle_lane_count == get_spi_flash_wait_cycle_lane_count(flash_command,flash_protocol_mode,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type);
      pre_data_cycle_count == get_spi_flash_pre_data_cycle_count(flash_command,wait_cycle_count,flash_protocol_mode,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type);
      pre_data_cycle_lane_count == get_spi_flash_pre_data_cycle_lane_count(flash_command,flash_protocol_mode,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type);
      instruction_lane_count == get_spi_flash_instruction_lane_count(flash_protocol_mode,flash_command,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type);
      address_frame_size inside {get_spi_flash_min_address_frame_size(flash_command,flash_protocol_mode,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type),get_spi_flash_max_address_frame_size(flash_command,flash_protocol_mode,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type)};
      address_frame inside {[get_spi_flash_min_address_frame(address_frame_size,flash_command,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type):get_spi_flash_max_address_frame(address_frame_size,flash_command,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type)]};
      instruction_frame_size == get_spi_flash_instruction_frame_size(flash_command,flash_protocol_mode,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type);
      attribute_bit_size == get_spi_flash_attribute_bit_size(flash_command);
      wrap_mode_bit_size == get_spi_flash_wrap_mode_bit_size(flash_command);
      wrap_mode inside {[get_spi_flash_min_wrap_mode(flash_command):get_spi_flash_max_wrap_mode(wrap_mode_bit_size,flash_command)]};
      plane_select_bit_size == get_spi_flash_plane_select_bit_size(flash_command,1'b0); //To calculate minimum sclk edges, required for hold parameters random value generation
      plane_select inside {[get_spi_flash_min_plane_select(flash_command):get_spi_flash_max_plane_select(plane_select_bit_size,flash_command)]};
      data_frame_size inside {[get_spi_flash_min_data_frame_size(flash_command,flash_attribute_bits,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type):get_spi_flash_max_data_frame_size(flash_command,flash_attribute_bits,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type)]};
      transfer_mode == get_spi_flash_transfer_mode(flash_command,flash_attribute_bits,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type);
      wait_cycle_count == get_spi_flash_wait_cycle_count(flash_command,flash_protocol_mode,transfer_mode,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type);
      double_transfer_rate_mode == get_spi_flash_dtr_mode(flash_command,flash_protocol_mode);
      instruction_frame == encode_spi_flash_command_opcode(flash_command,flash_protocol_mode,instruction_frame_size,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type); 
      xip_confirmation_n inside {[get_spi_flash_min_xip_confirmation_value(flash_command):get_spi_flash_max_xip_confirmation_value(flash_command)]};
      flash_command_type == get_spi_flash_command_type(flash_command,flash_attribute_bits,xSPI_command_list_index,xSPI_command_list_protocol_mode_index,xSPI_profile_type);
      flash_reset_sequence_length inside {[0:get_spi_flash_max_reset_sequence_length(flash_command)]};
      if (cfg.is_master) {
        total_transmit_edge == get_spi_flash_total_transmit_edge(address_frame_size,instruction_frame_size,data_frame_size,address_lane_count,instruction_lane_count,data_lane_count,flash_reset_sequence_length,wrap_mode_bit_size,plane_select_bit_size);
        total_sclk_edge == get_total_sclk_edge(flash_protocol_mode,double_transfer_rate_mode,address_frame_size,instruction_frame_size,data_frame_size,address_lane_count,instruction_lane_count,data_lane_count,wait_cycle_count,pre_data_cycle_count,flash_reset_sequence_length,wrap_mode_bit_size,plane_select_bit_size,attribute_bit_size);
        flash_assert_hold_after_sclk_count inside {[1:get_flash_assert_hold_after_sclk_count_max_value(total_transmit_edge)]};
        flash_sclk_to_hold_assert inside {[1:get_flash_sclk_to_hold_assert_max_value(cfg.sppr, cfg.spr)]};
        flash_sclk_to_hold_deassert inside {[1:get_flash_sclk_to_hold_deassert_max_value(cfg.sppr, cfg.spr)]};
        flash_hold_command_hold_time_sclk inside {[1:`SVT_SPI_MAX_HOLD_ASSERT_DELAY]};
      }
      else {
        flash_assert_hold_after_sclk_count == 0;
        flash_sclk_to_hold_assert == 0;
        flash_sclk_to_hold_deassert == 0;
        flash_hold_command_hold_time_sclk == 0;
      }

      if(cfg.spi_mem_cfg.mode_register_cfg.enable_dm_feature) {
        data_valid.size inside {0,constrant_solve_get_spi_flash_max_data_frame_size(flash_command_type,data_frame_size)};
      }  
      else {
        data_valid.size == 0;
      }  

      foreach(mem_upper_data_partition[i]) {
        if(mem_upper_data_partition[i] != null)
          mem_upper_data_partition[i].data_frame_size == data_frame_size;
      }
    }
    else {
      address_frame_size inside {[get_spi_generic_min_address_frame_size(cfg.enable_mem_core,cfg.spi_feature,cfg.frame_format): get_spi_generic_max_address_frame_size(cfg.enable_mem_core,cfg.spi_feature,cfg.frame_format)]};

      if (cfg.frame_format == svt_spi_types::SPI_MULTILANE){
        data_frame_size inside {[1:`SVT_SPI_MAX_DATA_TRANSFER]};
        instruction_lane_count inside {1,2,4,8};  
        address_lane_count inside {1,2,4,8};
        data_lane_count inside {1,2,4,8};
        data_lane_count >= instruction_lane_count;
        data_lane_count >= address_lane_count;
        instruction_frame_size%instruction_lane_count == 0;
        cfg.data_frame_width % data_lane_count == 0;
        address_frame inside {[0:get_spi_multilane_max_address_frame(transfer_mode,address_frame_size)]};
      }
      else if (cfg.frame_format == svt_spi_types::SPI_STD && cfg.spi_feature==svt_spi_types::UWIRE) {
        data_frame_size inside {[1:`SVT_SPI_MAX_DATA_TRANSFER]};
        uwire_control_word_lane_count == 1;
        transfer_mode inside {2'b00,2'b01};
        data_lane_count ==1;
        address_frame inside {[0:get_spi_std_max_address_frame(transfer_mode,address_frame_size)]};
        if (((transfer_mode == 2'b00) && (cfg.is_master)) || ((transfer_mode == 2'b01) && (~cfg.is_master))) {
          wait_cycle_count == 1'b1;
          wait_cycle_lane_count == 1'b1;
        }
        else {
          wait_cycle_count == 1'b0;
          wait_cycle_lane_count == 1'b0;
        }
        double_transfer_rate_mode == 0;
        timer_leading >= 1;
        timer_trailing >= 1;
        if (!cfg.uwire_enable_handshaking_mode) {
          uwire_deassert_start_bit == 1'b0; }
        if(uwire_transfer_state == svt_spi_types::SEQUENTIAL) {
          uwire_control_word_size == 1;
        }
      }
      else if (cfg.frame_format == svt_spi_types::SPI_SAFE) {
        data_frame_size == 0;
        data_lane_count == 1;
        address_lane_count == 1;
        address_frame_size == 0;
        instruction_lane_count == 1;
        instruction_frame_size == 0;
      }
      else {
        data_frame_size inside {[1:`SVT_SPI_MAX_DATA_TRANSFER]};
        address_lane_count == 1;
        instruction_lane_count == 1;
        data_lane_count == 1;
        instruction_frame_size inside {[0:`SVT_SPI_MAX_INST_FRAME_WIDTH]};
        instruction_frame_size%instruction_lane_count == 0;
        address_frame inside {[0:get_spi_std_max_address_frame(transfer_mode,address_frame_size)]};
      }
      if(double_transfer_rate_mode) {
        if(cfg.dtr_mode_select == svt_spi_types::INST_ADDRESS_DATA_PHASE || cfg.dtr_mode_select == svt_spi_types::ADDRESS_DATA_PHASE)
          address_frame_size%(address_lane_count*2) == 0;
        else
          address_frame_size%(address_lane_count) == 0;

        if(cfg.dtr_mode_select == svt_spi_types::INST_ADDRESS_DATA_PHASE)
          instruction_frame_size%(instruction_lane_count*2) == 0;
        else
          instruction_frame_size%(instruction_lane_count) == 0;
      }
      else {
        address_frame_size%(address_lane_count) == 0;
        instruction_frame_size%(instruction_lane_count) == 0;
      }
      total_sclk_edge == get_spibus_total_sclk_edge(double_transfer_rate_mode,address_frame_size,instruction_frame_size,data_frame_size,address_lane_count,instruction_lane_count,data_lane_count,wait_cycle_count,transfer_mode);
      total_transmit_edge == 1;
      xip_confirmation_n == 8'hFF;
      write_protect_n == 1'b1;
      read_device_id_with_power_down == 1'b1;
      flash_assert_hold_after_sclk_count == 0;
      flash_sclk_to_hold_assert == 0;
      flash_sclk_to_hold_deassert == 0;
      flash_hold_command_hold_time_sclk == 0;
      flash_reset_sequence_length == 0;
      flash_attribute_bits == 0;
      attribute_bit_size == 0;
      wrap_mode_bit_size == 0;
      plane_select_bit_size == 0;
      data_valid.size == 0;
      foreach(mem_upper_data_partition[i]) {
        if(mem_upper_data_partition[i] != null)
          mem_upper_data_partition[i].data_frame_size == 0;
      }
      xSPI_profile_type == svt_spi_types::NO_PROFILE;
      xSPI_command_list_index == -1;
      xSPI_command_list_protocol_mode_index == -1;
      jedec_hw_reset_cs_low_time_ns == 0;
    }

    if(cfg.is_master && cfg.enable_sclk_pause_feature) {
      sclk_pause_after_sclk_count.size <= total_sclk_edge;
      sclk_pause_after_sclk_count.size <= `SVT_SPI_MAX_PAUSE_COUNT;
      sclk_pause_after_sclk_count.size == sclk_pause_duration.size;

      foreach(sclk_pause_after_sclk_count[i]) {
        if(i>0) sclk_pause_after_sclk_count[i] > sclk_pause_after_sclk_count[i-1];
        sclk_pause_after_sclk_count[i] inside {[1:total_sclk_edge]};
        sclk_pause_duration[i] inside {[baud_rate_divisor*2:`SVT_SPI_MAX_PAUSE_DURATION]};
      }
    }
    else {
      sclk_pause_after_sclk_count.size == 0;
      sclk_pause_duration.size == 0;
    }
  }

  constraint reasonable_flash_attribute_bits {
    if(flash_command == svt_spi_types::TUNING_DATA_PATTERN_OPERATION)
      valid_spi_flash_attribute_bits(flash_protocol_mode,flash_attribute_bits) == 1;
  }

  constraint reasonable_spi_safe_frame_size {
    if (cfg.frame_format == svt_spi_types::SPI_SAFE)
      spi_safe_frame_size == 32;
    else
      spi_safe_frame_size == 0;
  }


