   * command opcode for DUAL_IO flash protocol mode.
   */ 
  extern virtual function int get_data_lane_count_dual_io(svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /**
   * This method returns the valid data lane count for the mentioned flash
   * command opcode for QUAD_IO flash protocol mode.
   */ 
  extern virtual function int get_data_lane_count_quad_io(svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /**
   * This method returns the valid data lane count for the mentioned flash
   * command opcode for OCTAL_IO flash protocol mode.
   */ 
  extern virtual function int get_data_lane_count_octal_io(svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /**
   * This method returns the wait cycle count for the mentioned flash
   * command.The value to be used while transmitting the transaction is also
   * determined by the dummy cycle program in configuration register along
   * with protocol mode of operation
   */ 
  extern virtual function int get_spi_flash_wait_cycle_count(svt_spi_types::flash_command_enum flash_command,svt_spi_types::flash_protocol_mode_enum flash_protocol_mode,bit [1:0] transfer_mode=2'b01, int xSPI_command_list_index=0, int xSPI_command_list_protocol_mode_index=0, svt_spi_types::xSPI_profile_type_enum xSPI_profile_type=svt_spi_types::NO_PROFILE);

  //----------------------------------------------------------------------------
  /** 
   * This method returns the pre data cycle count for the mentioned flash
   * command for all protocol modes.
   */
  extern virtual function int get_spi_flash_pre_data_cycle_count(svt_spi_types::flash_command_enum flash_command,int wait_cycle_count,svt_spi_types::flash_protocol_mode_enum flash_protocol_mode, int xSPI_command_list_index=0, int xSPI_command_list_protocol_mode_index=0, svt_spi_types::xSPI_profile_type_enum xSPI_profile_type=svt_spi_types::NO_PROFILE);

  //----------------------------------------------------------------------------
  /**
   * This method returns the valid pre data phase lane count for the mentioned flash
   * command opcode & flash protocol mode.
   */
  extern virtual function int get_spi_flash_pre_data_cycle_lane_count(svt_spi_types::flash_command_enum flash_command,svt_spi_types::flash_protocol_mode_enum flash_protocol_mode, int xSPI_command_list_index=0, int xSPI_command_list_protocol_mode_index=0, svt_spi_types::xSPI_profile_type_enum xSPI_profile_type=svt_spi_types::NO_PROFILE);

  //----------------------------------------------------------------------------
  /**
   * This method return the valid lower limit(3 byte/4byte) of #address_frame_size for the
   * mentioned flash command
   */ 
  extern virtual function int get_spi_flash_min_address_frame_size(svt_spi_types::flash_command_enum flash_command,svt_spi_types::flash_protocol_mode_enum flash_protocol_mode = svt_spi_types::EXTENDED_SPI, int xSPI_command_list_index=0, int xSPI_command_list_protocol_mode_index=0, svt_spi_types::xSPI_profile_type_enum xSPI_profile_type=svt_spi_types::NO_PROFILE);

  //----------------------------------------------------------------------------
  /**
   * This method return the valid upper limit of #address_frame_size for the
   * mentioned flash command
   */ 
  extern virtual function int get_spi_flash_max_address_frame_size(svt_spi_types::flash_command_enum flash_command,svt_spi_types::flash_protocol_mode_enum flash_protocol_mode = svt_spi_types::EXTENDED_SPI, int xSPI_command_list_index=0, int xSPI_command_list_protocol_mode_index=0, svt_spi_types::xSPI_profile_type_enum xSPI_profile_type=svt_spi_types::NO_PROFILE);

  //----------------------------------------------------------------------------
  /**
   * This method return the bit size of instruction code
   */ 
  extern virtual function int get_spi_flash_instruction_frame_size(svt_spi_types::flash_command_enum flash_command,svt_spi_types::flash_protocol_mode_enum flash_protocol_mode = svt_spi_types::EXTENDED_SPI, int xSPI_command_list_index=0, int xSPI_command_list_protocol_mode_index=0, svt_spi_types::xSPI_profile_type_enum xSPI_profile_type=svt_spi_types::NO_PROFILE);

  //----------------------------------------------------------------------------
  /**
   * This method return the bit size of Attribute Bits
   */ 
  extern virtual function int get_spi_flash_attribute_bit_size(svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /**
   * This method return the bit size of #wrap_mode transmitted during address
   * phase along with #address_frame
   */ 
  extern virtual function int get_spi_flash_wrap_mode_bit_size(svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /** 
   * This method return the bit size of #address_crc transmitted during address
   * phase along with #address_frame
   */ 
  extern virtual function int get_spi_flash_address_crc_frame_size(svt_spi_types::flash_command_enum flash_command,svt_spi_types::flash_protocol_mode_enum flash_protocol_mode);

  //----------------------------------------------------------------------------
  /**
   * This method return the bit size of #plane_select transmitted during address
   * phase along with #address_frame
   */ 
  extern virtual function int get_spi_flash_plane_select_bit_size(svt_spi_types::flash_command_enum flash_command,bit spi_nor_read_mode=0);

  //----------------------------------------------------------------------------
  /**
   * This method return the valid lower limit of Data byte count for mentioned
   * flash command
   */ 
  extern virtual function int get_spi_flash_min_data_frame_size(svt_spi_types::flash_command_enum flash_command,bit[`SVT_SPI_ATTRIBUTE_BIT_WIDTH-1:0] flash_attribute_bits=0, int xSPI_command_list_index=0, int xSPI_command_list_protocol_mode_index=0, svt_spi_types::xSPI_profile_type_enum xSPI_profile_type=svt_spi_types::NO_PROFILE);

  //----------------------------------------------------------------------------
  /**
   * This method return the valid upper limit of Data byte count for mentioned
   * flash command. The upper limit is controlled by macro SVT_SPI_MAX_DATA_TRANSFER.
   */ 
  extern virtual function int get_spi_flash_max_data_frame_size(svt_spi_types::flash_command_enum flash_command,bit[`SVT_SPI_ATTRIBUTE_BIT_WIDTH-1:0] flash_attribute_bits=0, int xSPI_command_list_index=0, int xSPI_command_list_protocol_mode_index=0, svt_spi_types::xSPI_profile_type_enum xSPI_profile_type=svt_spi_types::NO_PROFILE);

  //----------------------------------------------------------------------------
  /**
   * This method return whether DTR/DDR (data sample and driven on both edges)
   * is required in mentioned flash command
   */ 
  extern virtual function bit get_spi_flash_dtr_mode(svt_spi_types::flash_command_enum flash_command,svt_spi_types::flash_protocol_mode_enum flash_protocol_mode);

  //----------------------------------------------------------------------------
  /**
   * This method return whether mentioned flash command is a READ(2'b10) or Write(2'b01)
   * operation
   */ 
  extern virtual function bit[1:0] get_spi_flash_transfer_mode(svt_spi_types::flash_command_enum flash_command,bit[`SVT_SPI_ATTRIBUTE_BIT_WIDTH-1:0] flash_attribute_bits=0, int xSPI_command_list_index=0, int xSPI_command_list_protocol_mode_index=0, svt_spi_types::xSPI_profile_type_enum xSPI_profile_type=svt_spi_types::NO_PROFILE);

  //----------------------------------------------------------------------------
  /**
   * This method prints the valid flash commands for the selected PART Number
   */ 
  extern virtual function void print_spi_flash_command_rcvd();

  //----------------------------------------------------------------------------
  /**
   * This method return whether mentioned flash command is a valid opcode 
   */ 
  extern virtual function bit valid_spi_flash_command_rcvd(input svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /**
   * This method return whether mentioned Attribute Bits are valid for
   * the input flash protocol mode
   */ 
  extern virtual function bit valid_spi_flash_attribute_bits(svt_spi_types::flash_protocol_mode_enum flash_protocol_mode,bit[`SVT_SPI_ATTRIBUTE_BIT_WIDTH-1:0] attribute_bits);

  //----------------------------------------------------------------------------
  /**
   * This method set flash command category for mentioned flash command.
   * Please refer to svt_spi_types.sv for list of supported Flash command types.
   */ 
  extern virtual function void set_spi_flash_command_type(svt_spi_types::flash_command_enum flash_command,bit[`SVT_SPI_ATTRIBUTE_BIT_WIDTH-1:0] flash_attribute_bits=0, int xSPI_command_list_index=0, int xSPI_command_list_protocol_mode_index=0, svt_spi_types::xSPI_profile_type_enum xSPI_profile_type=svt_spi_types::NO_PROFILE);

  //----------------------------------------------------------------------------
  /**
   * This method return flash command category for mentioned flash command
   * Please refer to svt_spi_types.sv for list of supported Flash command types.
   */ 
  extern virtual function svt_spi_types::flash_command_type_enum get_spi_flash_command_type(svt_spi_types::flash_command_enum flash_command,bit[`SVT_SPI_ATTRIBUTE_BIT_WIDTH-1:0] flash_attribute_bits=0, int xSPI_command_list_index=0, int xSPI_command_list_protocol_mode_index=0, svt_spi_types::xSPI_profile_type_enum xSPI_profile_type=svt_spi_types::NO_PROFILE);

  //----------------------------------------------------------------------------
  /**
   * This method return lower limit #xip_confirmation_n field can take for mentioned
   * flash command
   */ 
  extern virtual function int get_spi_flash_min_xip_confirmation_value(svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /**
   * This method return upper limit #xip_confirmation_n field can take for mentioned
   * flash command
   */ 
  extern virtual function int get_spi_flash_max_xip_confirmation_value(svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /**
   * This method return lower limit #address_frame field can take for selected
   * address_frame_size and configured flash device 
   */ 
  extern virtual function bit [`SVT_SPI_MAX_ADDR_FRAME_WIDTH-1:0] get_spi_flash_min_address_frame(int address_frame_size,svt_spi_types::flash_command_enum flash_command, int xSPI_command_list_index=0, int xSPI_command_list_protocol_mode_index=0, svt_spi_types::xSPI_profile_type_enum xSPI_profile_type=svt_spi_types::NO_PROFILE);

  //----------------------------------------------------------------------------
  /**
   * This method return upper limit #address_frame field can take for selected
   * address_frame_size and configured flash device 
   */ 
  extern virtual function bit [`SVT_SPI_MAX_ADDR_FRAME_WIDTH-1:0] get_spi_flash_max_address_frame(int address_frame_size,svt_spi_types::flash_command_enum flash_command, int xSPI_command_list_index=0, int xSPI_command_list_protocol_mode_index=0, svt_spi_types::xSPI_profile_type_enum xSPI_profile_type=svt_spi_types::NO_PROFILE);

  //----------------------------------------------------------------------------
  /**
   * This method return the lower limit #wrap_mode field can take for selected
   * NAND Flash Device.
   */ 
  extern virtual function bit [`SVT_SPI_MAX_WRAP_CFG_BIT_WIDTH-1:0] get_spi_flash_min_wrap_mode(svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /**
   * This method return the upper limit #wrap_mode field can take for selected
   * NAND Flash Device.
   */ 
  extern virtual function bit [`SVT_SPI_MAX_WRAP_CFG_BIT_WIDTH-1:0] get_spi_flash_max_wrap_mode(int wrap_mode_bit_size,svt_spi_types::flash_command_enum flash_command);

    //----------------------------------------------------------------------------
  /**
   * This method return the lower limit #plane_select field can take for selected
   * NAND Flash Device.
   */ 
  extern virtual function bit [`SVT_SPI_MAX_PLANE_SELECT_CFG_BIT_WIDTH-1:0] get_spi_flash_min_plane_select(svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /**
   * This method return the upper limit #plane_select field can take for selected
   * NAND Flash Device.
   */ 
  extern virtual function bit [`SVT_SPI_MAX_PLANE_SELECT_CFG_BIT_WIDTH-1:0] get_spi_flash_max_plane_select(int plane_select_bit_size,svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /** This method returns the Baud Rate Divisor value for the current transaction. */ 
  extern virtual function int get_baud_rate_divisor_value(int sppr, int spr);

  //----------------------------------------------------------------------------
  /** This method returns the Total SCLK Edges in SPI FLASH mode based on the Protocol Mode, DDr mode and Instruction/Address/Wait/Data Phases etc. */
  extern virtual function int get_total_sclk_edge(svt_spi_types::flash_protocol_mode_enum flash_protocol_mode,bit double_transfer_rate_mode,int address_frame_size,int instruction_frame_size,int data_frame_size,int address_lane_count,int instruction_lane_count,int data_lane_count,int wait_cycle_count,int pre_data_cycle_count,int flash_reset_sequence_length,int wrap_mode_bit_size,int plane_select_bit_size,int attribute_bit_size);

  //----------------------------------------------------------------------------
  /** This method returns the Total SCLK Edges in SPI STD/SPI MULTILANE modes based on the DDR mode and Instruction/Address/Wait/Data Phases etc. */
  extern virtual function int get_spibus_total_sclk_edge(bit double_transfer_rate_mode,int address_frame_size,int instruction_frame_size,int data_frame_size,int address_lane_count,int instruction_lane_count,int data_lane_count,int wait_cycle_count,int transfer_mode);
  //----------------------------------------------------------------------------
  /**
   * This method returns upper limit of transmit sclk edge count value used while randomly calculating <br/>
   * the timing of Hold asserted by master in current transaction. <br/>
   * Hold Request is asserted after (#flash_assert_hold_after_sclk_count + #flash_sclk_to_hold_assert) delay <br/>  
   */ 
  extern virtual function int get_flash_assert_hold_after_sclk_count_max_value(int total_transmit_edge);

  //----------------------------------------------------------------------------
  /**
   * This method returns total transmit sclk edges driven by master for the current
   * transaction.
   */ 
  extern virtual function int get_spi_flash_total_transmit_edge(int address_frame_size,int instruction_frame_size,int data_frame_size,int address_lane_count,int instruction_lane_count,int data_lane_count,int flash_reset_sequence_length,int wrap_mode_bit_size,int plane_select_bit_size);

  //----------------------------------------------------------------------------
  /**
   * This method return upper limit of bus_clk cycles used for rand variable #flash_sclk_to_hold_assert 
   */ 
  extern virtual function int get_flash_sclk_to_hold_assert_max_value(int sppr, int spr);

  //----------------------------------------------------------------------------
  /**
   * This method return upper limit of bus_clk cycles used for rand variable #flash_sclk_to_hold_deassert 
   */ 
  extern virtual function int get_flash_sclk_to_hold_deassert_max_value(int sppr, int spr);

  //----------------------------------------------------------------------------
  /**
   * This method returns upper limit of Hold duration used <br/> 
   * while randomizing rand variable  #flash_hold_command_hold_time_sclk
   */ 
  extern virtual function int get_flash_hold_command_hold_time_sclk_max_value(int sppr, int spr, int total_transmit_edge,int flash_assert_hold_after_sclk_count,int flash_sclk_to_hold_assert);

  //----------------------------------------------------------------------------
  /**
   * This method returns upper limit of transmit sclk edge count value used while randomly calculating <br/>
   * the timing of SCLK Pause asserted by master in current transaction. <br/>
   */ 
  extern virtual function int get_sclk_pause_after_sclk_count_max_value(int total_transmit_edge);

  //----------------------------------------------------------------------------
  /**
   * This method encodes flash command binary value based on selected configuration feature 
   * and flash command enum.
   */ 
  extern virtual function bit [`SVT_SPI_MAX_INST_FRAME_WIDTH-1:0] encode_spi_flash_command_opcode(svt_spi_types::flash_command_enum flash_command,svt_spi_types::flash_protocol_mode_enum flash_protocol_mode,int instruction_frame_size=8, int xSPI_command_list_index=0, int xSPI_command_list_protocol_mode_index=0, svt_spi_types::xSPI_profile_type_enum xSPI_profile_type=svt_spi_types::NO_PROFILE); 

  //----------------------------------------------------------------------------
  /**
   * This method calculates the byte opcode of provided flash command for selected part number.
   */ 
  extern virtual function bit [`SVT_SPI_MAX_INST_FRAME_WIDTH-1:0] get_spi_flash_command_byte_opcode(svt_spi_types::flash_command_enum flash_command, int xSPI_command_list_index=0, svt_spi_types::xSPI_profile_type_enum xSPI_profile_type=svt_spi_types::NO_PROFILE);

  //----------------------------------------------------------------------------
  /**
   * This method decodes flash command type based on binary value and selected configuration feature. 
   */ 
  extern virtual function svt_spi_types::flash_command_enum decode_spi_flash_command_opcode(bit [`SVT_SPI_MAX_INST_FRAME_WIDTH-1:0] value,svt_spi_types::flash_protocol_mode_enum flash_protocol_mode,int instruction_frame_size=8);

  //----------------------------------------------------------------------------
  /**
   * This method decodes flash command based on 8 bit opcode value.
   */
  extern virtual function svt_spi_types::flash_command_enum decode_spi_flash_command_opcode_byte(bit [`SVT_SPI_MAX_INST_FRAME_WIDTH-1:0] value);

  //----------------------------------------------------------------------------
  /**
   * This method calculates and sets the transaction object fields based on selected
   * flash_command and protcol mode.
   */
  extern virtual function void set_flash_transaction_parameters(svt_spi_types::flash_protocol_mode_enum flash_protocol_mode,svt_spi_types::flash_command_enum flash_command);

  //---------------------------------------------------------------------------
  /**
   * This method returns the Reset sequence length based on selected Flash Part number.
   */ 
  extern virtual function int get_spi_flash_max_reset_sequence_length(svt_spi_types::flash_command_enum flash_command);


  //----------------------------------------------------------------------------
  /**
   * This method return the valid lower limit of #address_frame_size for the
   * SPI_STD/SPI_MULTILANE mode. 
   */ 
  extern virtual function int get_spi_generic_min_address_frame_size(bit enable_mem_core, svt_spi_types::spi_feature_enum spi_feature = svt_spi_types::SPI,svt_spi_types::frame_format_enum frame_format = svt_spi_types::SPI_STD);

  //----------------------------------------------------------------------------
  /**
   * This method return the valid upper limit of #address_frame_size for the
   * SPI_STD/SPI_MULTILANE mode. 
   */ 
  extern virtual function int get_spi_generic_max_address_frame_size(bit enable_mem_core, svt_spi_types::spi_feature_enum spi_feature = svt_spi_types::SPI,svt_spi_types::frame_format_enum frame_format = svt_spi_types::SPI_STD);


  //----------------------------------------------------------------------------
  /**
   * This method return upper limit #address_frame field can take for selected
   * address_frame_size in SPI_STD mode
   */ 
  extern virtual function bit [`SVT_SPI_MAX_ADDR_FRAME_WIDTH-1:0] get_spi_std_max_address_frame(bit [1:0] transfer_mode, int address_frame_size);

  //----------------------------------------------------------------------------
  /**
   * This method return upper limit #address_frame field can take for selected
   * address_frame_size in SPI_MULTILANE mode
   */ 
  extern virtual function bit [`SVT_SPI_MAX_ADDR_FRAME_WIDTH-1:0] get_spi_multilane_max_address_frame(bit [1:0] transfer_mode, int address_frame_size);

  //----------------------------------------------------------------------------
  /**
   * This method returns the minimum parallel mode value for the current flash command.
   */ 
  extern virtual function int get_spi_flash_min_parallel_mode(input svt_spi_types::flash_command_enum flash_command);
  
  //----------------------------------------------------------------------------
  /**
   * This method returns the maximum parallel mode value for the current flash command.
   */ 
  extern virtual function int get_spi_flash_max_parallel_mode(input svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /**
   * This method returns the Chip Physical Address. Required in Multi-Chip Mode
   */ 
  extern virtual function int get_chip_phy_address(bit [`SVT_SPI_MAX_ADDR_FRAME_WIDTH-1:0] addr_fr,svt_spi_types::flash_command_type_enum flash_cmd_type);
  
  //----------------------------------------------------------------------------
  /**
   * This method returns the minimum JEDEC HW Reset CS Low Time.
   */ 
  extern virtual function int get_spi_flash_min_jedec_hw_reset_cs_low_time();
  
  //----------------------------------------------------------------------------
  /**
   * This method returns the maximum JEDEC HW Reset CS Low Time.
   */ 
  extern virtual function int get_spi_flash_max_jedec_hw_reset_cs_low_time();
  
  //----------------------------------------------------------------------------
  /** This method return whether the command is FAST_READ type/XIP type or not*/
  extern virtual function bit whether_spi_flash_fast_read_or_xip_command(svt_spi_types::flash_command_enum flash_command,svt_spi_types::flash_protocol_mode_enum flash_protocol_mode);

  //----------------------------------------------------------------------------
  /** 
   * This method return whether current flash command supports Data Bytes on 16 lanes. <br/>
   * Ex: in APMEMORY device family "APS_OBR" parts only Memory Read/Write Commands are valid for this feature
   */
  extern virtual function bit whether_spi_flash_x16_data_lane_is_applicable(svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  // This method returns valid data_frame_size for selected flash command type
  extern virtual function int constrant_solve_get_spi_flash_max_data_frame_size(svt_spi_types::flash_command_type_enum flash_command_type,int data_frame_size);

