//------------------------------------------------------------------------------
function void svt_spi_transaction::check_valid_xSPI_command_list_index();
  if(xSPI_command_list_index == -1 || xSPI_profile_type == svt_spi_types::NO_PROFILE)
    `svt_fatal("post_randomize",$sformatf("Command Class with flash_command %s (xSPI Profile Type %s) not declared in Mode Register Cfg",flash_command,xSPI_profile_type));
  else if(xSPI_command_list_protocol_mode_index == -1)
    `svt_fatal("post_randomize",$sformatf("Protocol Mode %s not decalred in index %0d of Command Class not declared in Mode Register Cfg",flash_protocol_mode,xSPI_command_list_index));
endfunction

//------------------------------------------------------------------------------
function void svt_spi_transaction::set_pre_rand_mem_upper_partition_size();
  if(cfg.spi_mem_cfg.mode_register_cfg.mem_data_partition_size) begin
    mem_upper_data_partition = new[cfg.spi_mem_cfg.mode_register_cfg.mem_data_partition_size](mem_upper_data_partition);
    foreach(this.mem_upper_data_partition[i]) begin
      if (this.mem_upper_data_partition[i] == null) begin 
  `ifdef SVT_VMM_TECHNOLOGY
        this.mem_upper_data_partition[i] = new();
  `else
        this.mem_upper_data_partition[i] = svt_spi_mem_data_partition::type_id::create($sformatf("mem_upper_data_partition[%0d]",i));
  `endif
      end     
    end
  end
  else
    mem_upper_data_partition.delete;
endfunction

//------------------------------------------------------------------------------
function void svt_spi_transaction::set_post_rand_mem_upper_partition_size();
  if((cfg.spi_mem_cfg.mode_register_cfg.mem_data_partition_size ==0) || (cfg.spi_mem_cfg.mode_register_cfg.mem_data_partition_size && whether_spi_flash_x16_data_lane_is_applicable(flash_command) == 0))
    this.mem_upper_data_partition.delete;
endfunction

